public class IPRange
{
	private readonly long ipAddressBeginAsLong;

	private readonly long ipAddressEndAsLong;

	public IPRange(IPAddress ipAddress)
	{
		if (ipAddress.AddressFamily != AddressFamily.InterNetwork)
		{
			throw new ArgumentException("Only IPv4 addresses permitted.", "address");
		}
		ipAddressBeginAsLong = IPAddressToLong(ipAddress);
		ipAddressEndAsLong = IPAddressToLong(ipAddress);
	}

	public IPRange(IPAddress ipAddressBegin, IPAddress ipAddressEnd)
	{
		if (ipAddressBegin.AddressFamily != AddressFamily.InterNetwork)
		{
			throw new ArgumentException("Only IPv4 addresses permitted.", "begin");
		}
		if (ipAddressEnd.AddressFamily != AddressFamily.InterNetwork)
		{
			throw new ArgumentException("Only IPv4 addresses permitted.", "end");
		}
		ipAddressBeginAsLong = IPAddressToLong(ipAddressBegin);
		ipAddressEndAsLong = IPAddressToLong(ipAddressEnd);
	}

	public bool IsInRange(IPAddress address)
	{
		long num = IPAddressToLong(address);
		if (ipAddressBeginAsLong <= num)
		{
			return ipAddressEndAsLong >= num;
		}
		return false;
	}

	private long IPAddressToLong(IPAddress address)
	{
		long result = 0L;
		byte[] addressBytes = address.GetAddressBytes();
		if (addressBytes != null && addressBytes.Length != 0)
		{
			result = (long)(((ulong)addressBytes[0] << 24) + ((ulong)addressBytes[1] << 16) + ((ulong)addressBytes[2] << 8) + addressBytes[3]);
		}
		return result;
	}
}

public sealed class ForwarderEventArgs : EventArgs
{
	public string RelayNameSpace { get; } = string.Empty;

	public string RelayName { get; } = string.Empty;

	public ForwarderEventArgs(string relayName, string RelayNameSpace)
	{
		RelayName = relayName;
		this.RelayNameSpace = RelayNameSpace;
	}
}

